def check(x):
    if x > 0:
        return 'positive'
    elif x < 0:
        return 'negative'
    else:
        return 'zero'

class Calculator:
    def add(self, a, b):
        return a + b

    def subtract(self, a, b):
        return a - b

    def multiply(self, a, b):
        return a * b

def matrix_search(matrix, target):
    for row in matrix:
        for item in row:
            if item == target:
                return True
    return False

def process(data, config):
    results = []
    for item in data:
        if item.active:
            if item.score > config.threshold:
                try:
                    results.append(item.transform())
                except ValueError:
                    pass
            elif item.score < 0:
                results.append(item.default())
        else:
            if config.include_inactive:
                results.append(item)
    return results
